def classify(x):
    if x > 5:
        return 'high'
    elif x > 2:
        return 'medium'
    else:
        return 'low'

print(classify(7))

import math

def euclidean_distance(p1, p2):
    return math.sqrt(sum((a - b) ** 2 for a, b in zip(p1, p2)))

print(euclidean_distance([0, 0], [3, 4]))
